import React from 'react';

function TestImg({ itemData }) {
  return (
    <div className="flex gap-2 mt-10 w-full">
      {/* Left div with images */}
      <div className="w-1/2 overflow-auto">
        {itemData.photos?.map((pic, index) => (
          <div className="flex gap-2" key={index}>
            <img
              className="rounded-2xl object-cover"
              alt="img not found"
              src={"http://localhost:5000/" + pic}
            />
          </div>
        ))}
      </div>

      {/* Right div with information */}
      <div className="w-1/2 sticky top-0">
        {/* Content for the right div (information) */}
        <h1>{itemData.iname}</h1>
        {/* Add more content as needed */}
      </div>
    </div>
  );
}

export default TestImg;
